func describe(i interface{}) string {
    switch v := i.(type) {
    case int:
        return fmt.Sprintf("int: %d", v)
    case string:
        return fmt.Sprintf("string: %q", v)
    case []byte:
        return fmt.Sprintf("bytes: %d long", len(v))
    case nil:
        return "nil"
    default:
        return fmt.Sprintf("unknown type %T", v)
    }
}

